const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const header = req.headers.authorization || '';
  const token = header.startsWith('Bearer ') ? header.slice(7) : null;
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(401).json({ error: 'Invalid token' });
  }
}

app.get('/users', requireAuth, (req, res) => { /* ... */ });
```

### 3. Input Validation (OWASP A04)
No inputs today, so nothing to validate. Note that `express.json()` / `express.urlencoded()` are **not** enabled — if you add them, set size limits: `app.use(express.json({ limit: '100kb' }))` to mitigate DoS via large payloads.

### 4. Security Headers & Misconfiguration (OWASP A05)
Express ships with `X-Powered-By: Express` enabled and no security headers. Add `helmet`:
```js
const helmet = require('helmet');
app.disable('x-powered-by');
app.use(helmet());
